 1	import React, { FC } from 'react';
 2	
 3	import { tickLabels } from '@kubevirt-utils/components/Charts/ChartLabels/styleOverrides';
 4	import useResponsiveCharts from '@kubevirt-utils/components/Charts/hooks/useResponsiveCharts';
 5	import { Chart, ChartAxis, ChartLine, createContainer } from '@patternfly/react-charts';
 6	import { GridItem } from '@patternfly/react-core';
 7	
 8	import { ChartDataObject } from '../constants';
 9	
10	type MigrationsUtilizationChartProps = {
11	  chartData: ChartDataObject[];
12	  domain?: {
13	    x: [number, number];
14	    y: [number, number];
15	  };
16	  labels: any;
17	  tickFormat?: ((tick: any, index: number, ticks: any[]) => number | string) | any[];
18	  tickValues?: any[];
19	  title: string;
20	};
21	
22	const MigrationsUtilizationChart: FC<MigrationsUtilizationChartProps> = ({
23	  chartData,
24	  domain = null,
25	  labels,
26	  tickFormat = (y) => y,
27	  tickValues = null,
28	  title,
29	}) => {
30	  const { height, width } = useResponsiveCharts();
31	  const CursorVoronoiContainer = createContainer('voronoi', 'cursor');
32	
33	  return (
34	    <GridItem className="co-utilization-card__item">
35	      <div className="co-utilization-card__item-description">
36	        <h4>{title}</h4>
37	      </div>
38	      <div>
39	        <Chart
40	          containerComponent={
41	            <CursorVoronoiContainer
42	              activateData={false}
43	              cursorDimension="x"
44	              key={title}
45	              labels={labels}
46	              mouseFollowTooltips
47	              voronoiDimension="x"
48	            />
49	          }
50	          domain={domain}
51	          height={height}
52	          padding={{ bottom: 40, left: 80, right: 0, top: 40 }}
53	          scale={{ x: 'time', y: 'linear' }}
54	          width={width}
55	        >
56	          <ChartAxis
57	            axisComponent={<></>}
58	            dependentAxis
59	            showGrid
60	            style={{ tickLabels }}
61	            tickFormat={tickFormat}
62	            tickValues={tickValues}
63	          />
64	          <ChartLine data={chartData} />
65	        </Chart>
66	      </div>
67	    </GridItem>
68	  );
69	};
70	
71	export default MigrationsUtilizationChart;

